SELECT u.FirstName, u.LastName, m.HouseholdMemberID, m.RelationshipType, CAST(m.GroupId AS NVARCHAR(50)) AS MemberGroupId, CAST(primaryM.GroupId AS NVARCHAR(50)) AS PrimaryGroupId, CASE WHEN primaryM.GroupId IS NOT NULL AND primaryM.GroupId != '00000000-0000-0000-0000-000000000000' THEN 'LB' ELSE 'SB' END AS BillType FROM oe.Members m INNER JOIN oe.Users u ON m.UserId = u.UserId LEFT JOIN oe.Members primaryM ON primaryM.HouseholdId = m.HouseholdId AND primaryM.RelationshipType = 'P' WHERE m.HouseholdMemberID IN ('MW15990120','MW15990121','MW1599012102','MW1599012103','MW15990123','MW15990125','MW15990126','MW15990127','MW15990128','MW15990129','MW15990130','MW15990131','MW1599013101','MW15990132','MW15990133','MW15990134','MW15990135','MW1599013502','MW1599013503','MW1599013504','MW15990136','MW15990137','MW1599013701','MW15990138','MW15990139','MW1599013901','MW15990140','MW15990141','MW15990142','MW15990143','MW15990144','MW15990145','MW1599014502','MW15990146','MW15990147','MW15990148','MW15990149','MW15990150','MW15990151','MW15990152','MW15990187','MW15990191','MW15990250','MW15990251','MW1599025102','MW15990252','MW1599025201','MW1599025202','MW1599025203','MW15990253','MW15990255','MW15990256','MW15990257','MW15990258','MW15990259','MW15990260','MW15990264','MW1599026401','MW1599026402','MW1599026403','MW1599026404','MW15990294','MW1599029402','MW15990295','MW1599029501','MW15990297','MW15990300','MW15990301','MW15990302','MW15990304','MW15990320','MW1599032001','MW1599032002','MW1599032003','MW1599032004','MW15990321','MW15990322','MW15990323') ORDER BY primaryM.GroupId, m.HouseholdId, m.RelationshipType, u.LastName, u.FirstName;
